const start = Date.now();
const body = $('Validate Input1').item.json.body;

const test_type = body.test_type || '';
const patient   = body.patient_name || 'Невідомий';

// ── Нормалізація відповідей ──────────────────────────────────────────────────
let raw = body.answers || [];
let answers;
if (!Array.isArray(raw) && typeof raw === 'object') {
  answers = Object.keys(raw).sort((a,b)=>parseInt(a)-parseInt(b)).map(k=>parseInt(raw[k])||0);
} else {
  answers = raw.map(a=>parseInt(a)||0);
}

function resolveType(declared, ans) {
  if (['pcl5','minmult','schmishek'].includes(declared)) return declared;
  if (ans.length <= 20) return 'pcl5';
  if (ans.length <= 71) return 'minmult';
  return 'schmishek';
}
const resolved_type = resolveType(test_type, answers);

// ── PCL-5 (20 питань, шкала 0-4) ────────────────────────────────────────────
// Кластери DSM-5:
// B (1-5)  — Вторгнення
// C (6-7)  — Уникнення
// D (8-14) — Негативні зміни когніцій/настрою
// E (15-20)— Гіперзбудження
function score_pcl5(ans) {
  const a = ans.slice(0, 20);
  const total = a.reduce((s,v)=>s+v, 0);
  const B = a.slice(0,5).reduce((s,v)=>s+v,0);
  const C = a.slice(5,7).reduce((s,v)=>s+v,0);
  const D = a.slice(7,14).reduce((s,v)=>s+v,0);
  const E = a.slice(14,20).reduce((s,v)=>s+v,0);
  // Імовірний ПТСР: поріг ≥33 + хоча б один кластер перевищений
  const ptsd_probable = total >= 33 && (B>=10 || C>=4 || D>=14 || E>=12);
  let severity, severity_ua;
  if (total <= 32)      { severity='low';      severity_ua='Мінімальний'; }
  else if (total <= 44) { severity='moderate'; severity_ua='Легкий'; }
  else if (total <= 56) { severity='high';     severity_ua='Помірний'; }
  else                  { severity='severe';   severity_ua='Важкий'; }
  return {
    total, severity, severity_ua, ptsd_probable,
    subscales: {
      'B_Вторгнення': B,
      'C_Уникнення': C,
      'D_Когніції': D,
      'E_Збудження': E
    }
  };
}

// ── Міні-Мульт — 71 питання, власний опитувальник ───────────────────────────
// Питання згруповані по психопатологічних темах.
// Ключі (1-based) складені на основі змісту питань з документу.
// "yes" = відповідь "Так" (1) додає бал до шкали
// "no"  = відповідь "Ні"  (0) додає бал до шкали
const MM_SCALES = {
  'Іпохондрія_Hs': {
    yes: [2,3,6,21,22,28,32,39,45,46,64,65],
    no:  [30,50,59,61]
  },
  'Депресія_D': {
    yes: [11,15,18,19,22,24,33,34,36,37,41,54,56,57,58,63,64,67,70],
    no:  [5,49,59,62]
  },
  'Істерія_Hy': {
    yes: [2,3,6,7,14,21,22,28,32,39,45,46,65],
    no:  [17,19,26,29,38,51]
  },
  'Психопатія_Pd': {
    yes: [10,13,16,18,23,24,26,33,43,55,56,63,67],
    no:  [9,17,29,42,50,57,62]
  },
  'Параноя_Pa': {
    yes: [10,12,13,14,20,26,36,37,41,43,57,63,67,68],
    no:  [25,38,51,52,59]
  },
  'Психастенія_Pt': {
    yes: [2,3,7,15,19,22,24,37,38,41,47,54,56,58,63,67,70],
    no:  [30,59,62]
  },
  'Шизофренія_Sc': {
    yes: [7,8,20,24,26,27,33,36,37,41,43,44,46,47,53,54,56,63,65,67,70],
    no:  [17,29,38,49,50,52,59,62]
  },
  'Гіпоманія_Ma': {
    yes: [4,5,16,23,26,42,43,51,53,55,58,64,67],
    no:  [9,36,50,57,62]
  },
  'Соціальна_інтроверсія_Si': {
    yes: [8,25,40,52,53,68],
    no:  [4,14,16,17,28,49,55,64,66]
  },
};

function score_minmult(ans) {
  const a = ans.slice(0, 71);
  const scales = {};
  for (const [scale, keys] of Object.entries(MM_SCALES)) {
    let s = 0;
    for (const k of keys.yes) { if (k<=a.length && a[k-1]===1) s++; }
    for (const k of keys.no)  { if (k<=a.length && a[k-1]===0) s++; }
    scales[scale] = s;
  }
  const clinical_names = Object.keys(MM_SCALES);
  const values = clinical_names.map(n=>scales[n]);
  const maxVal = Math.max(...values);
  const total  = values.reduce((s,v)=>s+v, 0);
  const peak_scale = clinical_names[values.indexOf(maxVal)];

  // Шкали достовірності
  const L = [6,9,15,17,29,30,35,50,59,62].filter(k=>k<=a.length&&a[k-1]===1).length;
  const F = [7,10,13,14,20,23,24,26,27,31,33,36,37,41,43,44,46,47,51,53,54,55,56,58,63,65,67,70].filter(k=>k<=a.length&&a[k-1]===1).length;
  const K = [9,26,30,57,62].filter(k=>k<=a.length&&a[k-1]===1).length +
            [8,19,21,22,25,38,40,42,50,52,59,68].filter(k=>k<=a.length&&a[k-1]===0).length;

  let severity, severity_ua;
  if (maxVal <= 4)       { severity='low';      severity_ua='В нормі'; }
  else if (maxVal <= 7)  { severity='moderate'; severity_ua='Субнорма'; }
  else if (maxVal <= 10) { severity='high';     severity_ua='Відхилення'; }
  else                   { severity='severe';   severity_ua='Виражений'; }

  return {
    total, severity, severity_ua, peak_scale,
    subscales: scales,
    validity: { L, F, K },
    elevated_scales: clinical_names.filter(n=>scales[n]>=8)
  };
}

// ── Шмішек — 88 питань, 10 шкал акцентуацій (Леонгард) ─────────────────────
// Ключі прив'язані до змісту власних питань з документу
const SCH_SCALES = {
  'Гіпертимія': {
    yes: [7,11,36,50],
    no:  [30,58]
  },
  'Дистимія': {
    yes: [15,38,46,55,64,71],
    no:  [1,14,28,48]
  },
  'Циклотимія': {
    yes: [3,16,72,76],
    no:  []
  },
  'Збудливість': {
    yes: [10,33,52,75,79,83],
    no:  []
  },
  'Застрягання': {
    yes: [21,31,56,69,73],
    no:  [2,27,47]
  },
  'Педантизм': {
    yes: [13,17,29,34,41,43],
    no:  [36]
  },
  'Тривожність': {
    yes: [5,11,26,38,54,60],
    no:  [1,6]
  },
  'Емотивність': {
    yes: [3,15,37,45,68,78],
    no:  [58]
  },
  'Демонстративність': {
    yes: [4,18,24,28,40,64,66,80,85],
    no:  [51]
  },
  'Екзальтованість': {
    yes: [7,36,57,72,77,82,86],
    no:  []
  },
};

function score_schmishek(ans) {
  const a = ans.slice(0, 88);
  const scales = {};
  for (const [scale, keys] of Object.entries(SCH_SCALES)) {
    let s = 0;
    for (const k of keys.yes) { if (k<=a.length && a[k-1]===1) s++; }
    for (const k of keys.no)  { if (k<=a.length && a[k-1]===0) s++; }
    // Нормування до 24 балів (як в оригінальному Шмішеку)
    const max_keys = (keys.yes.length + keys.no.length);
    scales[scale] = max_keys > 0 ? Math.round(s * 24 / max_keys) : 0;
  }
  const entries   = Object.entries(scales);
  const peak      = entries.sort(([,a],[,b])=>b-a)[0];
  const total     = entries.reduce((s,[,v])=>s+v, 0);
  const accentuated = Object.entries(scales).filter(([,v])=>v>=19).map(([k])=>k);

  let severity, severity_ua;
  if (accentuated.length === 0)     { severity='low';      severity_ua='В нормі'; }
  else if (accentuated.length <= 2) { severity='moderate'; severity_ua='Акцентуація'; }
  else if (accentuated.length <= 4) { severity='high';     severity_ua='Виражена'; }
  else                              { severity='severe';   severity_ua='Дуже виражена'; }

  return {
    total, severity, severity_ua,
    subscales: Object.fromEntries(Object.entries(scales).sort(([,a],[,b])=>b-a)),
    accentuated_types: accentuated,
    peak_type: peak?.[0],
    peak_score: peak?.[1]
  };
}

// ── Запуск ───────────────────────────────────────────────────────────────────
const scorers    = { pcl5: score_pcl5, minmult: score_minmult, schmishek: score_schmishek };
const test_names = { pcl5:'PCL-5 (ПТСР)', minmult:'Міні-Мульт (MMPI)', schmishek:'Шмішек (акцентуації)' };

if (!scorers[resolved_type]) throw new Error('Unknown test_type: ' + resolved_type);

const result = scorers[resolved_type](answers);
const scoring_time_ms = Date.now() - start;

return [{
  json: {
    ...body,
    answers,
    test_type:        resolved_type,
    test_name:        test_names[resolved_type],
    score:            result.total,
    severity:         result.severity,
    severity_ua:      result.severity_ua,
    subscales:        result.subscales,
    scoring_time_ms,
    // Поля специфічні для кожного тесту
    ...(result.ptsd_probable     !== undefined && { ptsd_probable:     result.ptsd_probable }),
    ...(result.peak_scale        !== undefined && { peak_scale:        result.peak_scale }),
    ...(result.elevated_scales   !== undefined && { elevated_scales:   result.elevated_scales }),
    ...(result.validity          !== undefined && { validity:          result.validity }),
    ...(result.accentuated_types !== undefined && { accentuated_types: result.accentuated_types }),
    ...(result.peak_type         !== undefined && { peak_type:         result.peak_type }),
    ...(result.peak_score        !== undefined && { peak_score:        result.peak_score }),
  }
}];
